$ErrorActionPreference = "Stop"

function Write-B64([string]$Path,[string]$B64){
  if (Test-Path $Path) { Copy-Item $Path ($Path + ".bak") -Force }
  [System.IO.File]::WriteAllBytes($Path, [System.Convert]::FromBase64String($B64))
  Write-Host ("OK  -> " + $Path)
}

Write-B64 "C:\CORE\apps\core-market\src\lib\tool-editor\src\components\ToolEditor.jsx" ""

Write-B64 "C:\CORE\apps\core-market\src\app\admin\pages\AdminToolEditor.tsx" ""

Write-Host "Listo. Backups guardados como *.bak"
